ndercontrol,willglobalgrowthbeabletosupportEurope’srecovery.Butthatwill nothappenin2023.', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:02+00:00", "source_pdf_sha1": "40dfeee2f26b", "answer_pdf_sha1": "9e2c31161d8b", "source_family": "moex-gov-tw", "moex": {"exam_code": "113140", "c": "304", "s": "0215", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "英文", "year": "113", "exam_name": "113年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "aviation", "civil_category": "航務管理"}'::jsonb, NULL),
